import { useId, useMemo, useState, type KeyboardEvent } from 'react'
import { Plus } from 'lucide-react'
import { cn } from '@/lib/utils'
import { type PropertyEditorProps } from '@/data/api'
import { Block } from '@/data/block'
import { useTypes } from '@/hooks/typeRegistry.js'
import { useAutocompleteListbox } from '@/hooks/useAutocompleteListbox.js'
import { FloatingListbox } from '@/components/ui/floating-listbox.js'
import { TypeChip } from '@/components/typeChip/TypeChip'

export interface TypeOption {
  id: string
  label: string
  description?: string
  hideFromCompletion: boolean
}

/** Which option Enter/Tab commits. Pure — exported for direct testing.
 *
 *  A user-defined type can share a label with an infrastructure
 *  kernel/plugin type ("page", "Media"). Typing that label into a TYPE
 *  picker almost always means the completion-offered one — preferring
 *  it matches the `#` autocomplete's resolution (the ref-target picker
 *  currently resolves such collisions by registration order — a known
 *  gap, not a policy to be consistent with). A sole infrastructure
 *  exact match still commits (the panel's dropdown deliberately lists
 *  everything, and it's the visibly highlighted row). An explicit
 *  highlight (arrows / hover → `navigated`) beats the exact-match
 *  shortcut — committing something other than the highlighted row
 *  contradicts what the user is looking at. */
export const resolveCommitTarget = (args: {
  options: readonly TypeOption[]
  filtered: readonly TypeOption[]
  /** Trimmed, lowercased query. */
  queryText: string
  navigated: boolean
  activeIndex: number
  selectedIds: ReadonlySet<string>
}): TypeOption | undefined => {
  const exactMatches = args.options.filter(option =>
    option.id.toLowerCase() === args.queryText ||
    option.label.toLowerCase() === args.queryText)
  const exact = exactMatches.find(option => !option.hideFromCompletion) ?? exactMatches[0]
  return !args.navigated && exact && !args.selectedIds.has(exact.id)
    ? exact
    : args.filtered[args.activeIndex] ?? args.filtered[0]
}

const normalizedTypes = (value: readonly string[]): readonly string[] =>
  Array.from(new Set(value.map(type => type.trim()).filter(Boolean)))

/** A user-defined type's id is the type-definition block's uuid —
 *  meaningless to a human picking the type. Hide it from the dropdown
 *  so a long uuid can't visually drown the label even in narrow panels;
 *  kernel ids ("page", "block-type", etc.) are short and human-readable
 *  and stay visible as disambiguation alongside their label. */
const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i
const isOpaqueId = (id: string): boolean => UUID_PATTERN.test(id)

export function TypesPropertyEditor({
  value,
  block,
}: PropertyEditorProps<readonly string[]>) {
  const listboxId = useId()
  const [shellElement, setShellElement] = useState<HTMLDivElement | null>(null)
  const typedBlock = block instanceof Block ? block : null
  const readOnly = typedBlock?.repo.isReadOnly ?? true
  const selected = useMemo(() => normalizedTypes(value), [value])
  const selectedSet = useMemo(() => new Set(selected), [selected])
  const [query, setQuery] = useState('')
  const [open, setOpen] = useState(false)
  // True once the user explicitly highlighted a row (arrows / hover)
  // since last typing — an index-based proxy can't tell "navigated
  // back to row 0" from "never navigated".
  const [navigated, setNavigated] = useState(false)
  const typesRegistry = useTypes()
  const options = useMemo<TypeOption[]>(() => Array.from(typesRegistry.values()).map(type => ({
    id: type.id,
    label: type.label ?? type.id,
    description: type.description,
    hideFromCompletion: type.hideFromCompletion === true,
  })), [typesRegistry])
  const queryText = query.trim().toLowerCase()
  const filtered = useMemo(() => options.filter(option => {
    if (selectedSet.has(option.id)) return false
    if (!queryText) return true
    return option.id.toLowerCase().includes(queryText) ||
      option.label.toLowerCase().includes(queryText)
  }), [options, queryText, selectedSet])

  const setTypes = (nextTypes: readonly string[]) => {
    if (!typedBlock || readOnly) return
    void typedBlock.repo.setBlockTypes(typedBlock.id, normalizedTypes(nextTypes))
  }

  const addType = (typeId: string) => {
    if (!typesRegistry.has(typeId) || selectedSet.has(typeId)) return
    setTypes([...selected, typeId])
    setQuery('')
    setOpen(false)
  }

  const removeType = (typeId: string) => {
    setTypes(selected.filter(selectedType => selectedType !== typeId))
  }

  // Shared listbox core: arrow navigation, option mouse handlers, and
  // the aria-activedescendant / option-id wiring (same as
  // PropertyPicker / RefPropertyEditor). Enter/Tab are handled in the
  // keydown below instead of delegated — their commit runs through
  // resolveCommitTarget (exact-match policy), not plain
  // commit-the-active-row, and an empty query must not commit at all.
  const listbox = useAutocompleteListbox({
    itemCount: filtered.length,
    setOpen,
    listboxId,
    onCommit: index => {
      const option = filtered[index]
      if (!option) return false
      addType(option.id)
      return true
    },
  })

  const commitCurrentQuery = (): boolean => {
    const option = resolveCommitTarget({
      options, filtered, queryText, navigated,
      activeIndex: listbox.activeIndex,
      selectedIds: selectedSet,
    })
    if (!option) return false
    addType(option.id)
    return true
  }

  const handleInputKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
    if (readOnly) return

    if (event.key === 'ArrowDown' || event.key === 'ArrowUp') {
      setNavigated(true)
      listbox.onKeyDown(event)
      return
    }

    if ((event.key === 'Enter' || event.key === 'Tab') && query.trim()) {
      if (commitCurrentQuery()) event.preventDefault()
      return
    }

    if (event.key === 'Backspace' && !query && selected.length > 0) {
      event.preventDefault()
      removeType(selected[selected.length - 1])
      return
    }

    if (event.key === 'Escape') {
      setOpen(false)
    }
  }

  return (
    <div
      className="min-w-0"
      onBlur={() => {
        window.setTimeout(() => setOpen(false), 120)
      }}
    >
      <div
        ref={setShellElement}
        className="flex min-h-7 min-w-0 flex-wrap items-center gap-1.5 rounded-md border border-transparent bg-transparent px-0 py-0.5 focus-within:border-input focus-within:px-1.5"
      >
        {/* The panel is the full management surface: every chip keeps
            its ✕ (including plumbing types the block row withholds it
            from), and re-adding anything is one dropdown away. */}
        {selected.map(typeId => (
          <TypeChip
            key={typeId}
            typeId={typeId}
            type={typesRegistry.get(typeId)}
            onRemove={readOnly ? undefined : () => removeType(typeId)}
          />
        ))}
        <input
          className="h-6 min-w-[8rem] flex-1 bg-transparent text-sm outline-none placeholder:text-muted-foreground/55 disabled:cursor-not-allowed disabled:opacity-60"
          value={query}
          placeholder="Add type"
          disabled={readOnly}
          role="combobox"
          aria-label="Add block type"
          aria-expanded={open}
          aria-controls={listboxId}
          aria-autocomplete="list"
          aria-activedescendant={open && !readOnly ? listbox.activeDescendantId : undefined}
          onFocus={() => setOpen(true)}
          onChange={event => {
            setQuery(event.target.value)
            listbox.setActiveIndex(0)
            setNavigated(false)
            setOpen(true)
          }}
          onKeyDown={handleInputKeyDown}
        />
      </div>

      <FloatingListbox
        id={listboxId}
        open={open && !readOnly}
        anchorElement={shellElement}
        maxWidth={352}
        maxHeight={224}
      >
        {filtered.length > 0 ? filtered.map((option, index) => {
          const optionProps = listbox.getOptionProps(index)
          return (
          <button
            key={option.id}
            type="button"
            {...optionProps}
            className={cn(
              'flex w-full items-center gap-2 rounded-sm px-2 py-1.5 text-left',
              index === listbox.activeIndex ? 'bg-accent text-accent-foreground' : 'hover:bg-accent hover:text-accent-foreground',
            )}
            onMouseEnter={() => {
              setNavigated(true)
              optionProps.onMouseEnter()
            }}
          >
            <Plus className="h-3.5 w-3.5 shrink-0 text-muted-foreground" />
            <span className="min-w-0 flex-1 truncate">{option.label}</span>
            {option.label !== option.id && !isOpaqueId(option.id) && (
              // Auxiliary id badge — shown only for human-readable ids
              // (kernel: "page", "block-type", "panel:properties"). User-
              // defined types have uuid ids that carry no signal to the
              // picker; hiding them keeps the label fully visible even
              // in narrow panel widths.
              <span className="min-w-0 max-w-[12rem] truncate text-xs text-muted-foreground">{option.id}</span>
            )}
          </button>
          )
        }) : (
          <div className="px-2 py-1.5 text-muted-foreground">No matching types</div>
        )}
      </FloatingListbox>
    </div>
  )
}
